const body = items[0].json.body || items[0].json;

const evalData = {
  overall_score: body.overall_score || 0,
  knowledge_score: body.knowledge_score || 0,
  critical_score: body.critical_score || 0,
  application_score: body.application_score || 0,
  referencing_score: body.referencing_score || 0,
  structure_score: body.structure_score || 0,
  subject: body.subject || '',
  issues: body.issues || [],
  strengths: body.strengths || []
};

const prompt = `You are an expert academic writing coach. Based on this evaluation data, create a detailed "Distinction Guide" that shows the student exactly how to improve their paper to distinction level (75%+).

Return ONLY valid JSON:
{
  "current_level": "fail|pass|credit|distinction",
  "target_score": 75,
  "gap_analysis": "brief analysis of what needs to improve",
  "priority_actions": [
    {
      "criterion": "Knowledge|Critical Thinking|Application|Referencing|Structure",
      "current_score": number,
      "target_score": 75,
      "action": "specific action to take",
      "example_before": "current weak example from paper",
      "example_after": "improved version",
      "impact": "high|medium|low"
    }
  ],
  "quick_wins": ["easy improvements that boost score fast"],
  "writing_tips": ["specific writing improvement suggestions"]
}

Evaluation data:
${JSON.stringify(evalData, null, 2)}`;

return [{ json: { prompt } }];

const response = items[0].json;
let text = response.text || response.output || '';

if (!text && response.candidates && response.candidates.length > 0) {
  const parts = response.candidates[0].content.parts;
  if (parts && parts.length > 0) text = parts[0].text;
}

if (!text) {
  return [{ json: { error: 'Guide generation failed. Please try again.' } }];
}

let jsonStr = text.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

const firstBrace = jsonStr.indexOf('{');
if (firstBrace > 0) jsonStr = jsonStr.substring(firstBrace);
if (!jsonStr.endsWith('}')) {
  const lastBrace = jsonStr.lastIndexOf('}');
  if (lastBrace > 0) jsonStr = jsonStr.substring(0, lastBrace + 1);
}

try {
  const parsed = JSON.parse(jsonStr);
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { error: 'Guide generation failed. Please try again.' } }];
}
